import Card from "../Card/Card";
import React from "react";

function Cards({ characters }) {
  const onClose = () => {
    window.alert("Emulamos que se cierra la card");
  };

  return (
    <div>
      {characters?.map(({ name, species, gender, image, id }) => {
        return (
          <Card
            key={id}
            name={name}
            species={species}
            gender={gender}
            image={image}
            onClose={onClose}
          />
        );
      })}
    </div>
  );
}

export default Cards;
